import React, { useEffect, useState } from 'react';
import { useSprings, animated } from '@react-spring/web';
import Icon from './Icon';
import icons from '../config/iconExps';

interface ExpsProps {
  toggle: boolean;
}

/** Temps pour laisser finir le stagger inversé + ressorts avant démontage. */
const CLOSE_UNMOUNT_MS = 1600;
const STAGGER_MS = 48;
/** Délai commun après la barre (ouverture seulement). */
const OPEN_LEAD_MS = 210;
/** Largeur approximative (icône 64px + marge) pour le décalage miroir sur l’axe X. */
const ICON_CELL_PX = 72;

/** Position cachée (entrée par la gauche) : ordre horizontal inversé par rapport au placement final. */
function hiddenXLeft(n: number, i: number): number {
  return -150 + (n - 1 - 2 * i) * ICON_CELL_PX;
}

const Exps = ({ toggle }: ExpsProps) => {
  const n = icons.length;
  // Avec `deps`, useSprings renvoie [springs, ref] — il faut destructurer sinon .map casse la page.
  const [expsSprings] = useSprings(
    n,
    (i) => ({
      from: { x: hiddenXLeft(n, i) },
      to: { x: toggle ? 0 : hiddenXLeft(n, i) },
      config: { tension: 305, friction: 19, mass: 0.58 },
      /** Ouverture : de gauche à droite elles se « rangent » ; fermeture : inverse. */
      delay:
        (toggle ? i : n - 1 - i) * STAGGER_MS + (toggle ? OPEN_LEAD_MS : 0),
    }),
    [toggle]
  );

  const [display, setDisplay] = useState(false);

  useEffect(() => {
    if (toggle && !display) {
      setDisplay(true);
    }
    if (!toggle && display) {
      const t = setTimeout(() => {
        setDisplay(false);
      }, CLOSE_UNMOUNT_MS);
      return () => clearTimeout(t);
    }
  }, [display, toggle]);

  return (
    <div className="relative left-[45px] top-[10px] flex h-[100px] w-[600px] flex-row flex-wrap items-center justify-start p-[5px] max-[750px]:left-0 max-[750px]:top-5 max-[750px]:h-[100px] max-[750px]:w-[280px] max-[750px]:flex-wrap max-[750px]:justify-start">
      {display &&
        expsSprings.map((styles, index) => (
          <animated.div
            key={index}
            style={{
              transform: styles.x.to((x: number) => `translateX(${x}px)`),
              willChange: 'transform',
            }}
          >
            <Icon
              name={icons[index].name}
              title={icons[index].title}
              url={icons[index].url}
              background={false}
            />
          </animated.div>
        ))}
    </div>
  );
};

export default Exps;
